#include <bits/stdc++.h>
using namespace std;

int N;
int g[30][30];
bool vis[30][30];
int dx[4] = {1,-1,0,0};
int dy[4] = {0,0,1,-1};

int bfs(int sy, int sx) {
    queue<pair<int,int>> q;
    q.push({sy, sx});
    vis[sy][sx] = true;
    int cnt = 0;
    while (!q.empty()) {
        auto [y, x] = q.front(); q.pop();
        cnt++;
        for (int d = 0; d < 4; d++) {
            int ny = y + dy[d], nx = x + dx[d];
            if (ny < 0 || ny >= N || nx < 0 || nx >= N) continue;
            if (vis[ny][nx] || g[ny][nx] == 0) continue;
            vis[ny][nx] = true;
            q.push({ny, nx});
        }
    }
    return cnt;
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> N;
    for (int i = 0; i < N; i++) {
        string s; cin >> s;
        for (int j = 0; j < N; j++) g[i][j] = s[j] - '0';
    }
    vector<int> sizes;
    for (int i = 0; i < N; i++)
        for (int j = 0; j < N; j++)
            if (g[i][j] == 1 && !vis[i][j]) sizes.push_back(bfs(i, j));
    sort(sizes.begin(), sizes.end());
    cout << sizes.size() << "\n";
    for (int s : sizes) cout << s << "\n";
    return 0;
}
